```javascript
// proxy.js - Free Fire Proxy Sunucusu (Node.js + Express)
// Bu dosya tam bir proxy ve yönetim paneli sağlar.
// Türkçe yorumlarla her aşama açıklanmıştır.

const express = require('express');
const fs = require('fs');
const path = require('path');
const jwt = require('jsonwebtoken');
const { v4: uuidv4 } = require('uuid');
const crypto = require('crypto');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

// Global ayarlar (config.json yoksa varsayılan)
let globalConfig = {
  port: 4500,
  jwtSecret: '369SD-FREE-FIRE-PROXY-2025',
  sessionDurationHours: 24,
  maxLogEntries: 1000,
  assetCacheSeconds: 300,
  adminPassword: 'vortexia2025'
};
if (fs.existsSync('./config.json')) {
  globalConfig = { ...globalConfig, ...JSON.parse(fs.readFileSync('./config.json')) };
}
const JWT_SECRET = globalConfig.jwtSecret;

// Veri dosyalarının okunması/yazılması için yardımcılar
function readJSON(file, defaultVal = []) {
  try {
    if (fs.existsSync(file)) return JSON.parse(fs.readFileSync(file, 'utf8'));
  } catch (e) {}
  return defaultVal;
}
function writeJSON(file, data) {
  fs.writeFileSync(file, JSON.stringify(data, null, 2));
}

// Kullanıcı verisi: her bir lisans anahtarı için ayarlar
let users = readJSON('./users.json', {}); // format: { "369SD-XXXXXX": { owner, expires, max_devices, features: {...}, devices: [] } }
let sessions = readJSON('./sessions.json', {}); // { session_id: { userKey, expireAt, ips: [] } }
let logs = readJSON('./logs.json', []);

// Anahtar format kontrolü
function isValidKey(key) {
  return /^369SD-[A-Za-z0-9]{6}$/.test(key);
}

// Oturum doğrulama middleware
function authMiddleware(req, res, next) {
  const sessionId = req.headers['x-session-id'] || req.query.session_id;
  if (!sessionId) return res.status(401).json({ error: 'Oturum kimliği gerekli' });
  const session = sessions[sessionId];
  if (!session || new Date(session.expireAt) < new Date()) {
    return res.status(403).json({ error: 'Oturum geçersiz veya süresi dolmuş' });
  }
  req.userKey = session.userKey;
  next();
}

// Admin paneli için basit auth
function adminAuth(req, res, next) {
  const pass = req.headers['x-admin-pass'] || req.query.pass;
  if (pass !== globalConfig.adminPassword) return res.status(403).json({ error: 'Yetkisiz' });
  next();
}

// Rastgele gecikme ve sahte başlık ekleme (anti-detection)
app.use((req, res, next) => {
  // Sahte User-Agent ve cihaz ID
  res.setHeader('X-Device-ID', 'Android-' + Math.random().toString(36).substring(2, 15));
  // Ufak rastgele gecikme (50-150ms)
  const delay = Math.floor(Math.random() * 100) + 50;
  setTimeout(next, delay);
});

// Log tutma fonksiyonu
function addLog(userKey, ip, endpoint) {
  const entry = { timestamp: new Date().toISOString(), userKey, ip, endpoint };
  logs.push(entry);
  if (logs.length > globalConfig.maxLogEntries) {
    logs = logs.slice(logs.length - globalConfig.maxLogEntries);
  }
  writeJSON('./logs.json', logs);
}

// Kullanıcı dosyasına kayıt
function saveUsers() {
  writeJSON('./users.json', users);
}
function saveSessions() {
  writeJSON('./sessions.json', sessions);
}

// --------------------------------------
// ENDPOINTLER
// --------------------------------------

// POST /auth - Anahtar doğrulama ve oturum oluşturma
app.post('/auth', (req, res) => {
  const { key } = req.body;
  if (!key || !isValidKey(key)) {
    return res.status(400).json({ error: 'Geçersiz anahtar formatı. 369SD-XXXXXX şeklinde olmalı.' });
  }
  const user = users[key];
  if (!user) {
    return res.status(404).json({ error: 'Lisans anahtarı bulunamadı' });
  }
  if (new Date(user.expires) < new Date()) {
    return res.status(403).json({ error: 'Lisans süresi dolmuş' });
  }
  // Yeni bir oturum oluştur
  const sessionId = uuidv4();
  const expireAt = new Date(Date.now() + globalConfig.sessionDurationHours * 60 * 60 * 1000).toISOString();
  sessions[sessionId] = {
    userKey: key,
    expireAt: expireAt,
    createdAt: new Date().toISOString(),
    ips: []
  };
  saveSessions();
  addLog(key, req.ip, '/auth');
  res.json({ session_id: sessionId, expires: expireAt });
});

// GET /version.php - Genel veya özel versiyon kontrolü
app.get('/version.php', (req, res) => {
  const sessionId = req.headers['x-session-id'] || req.query.session_id;
  const user = sessionId ? users[sessions[sessionId]?.userKey] : null;
  const baseResponse = {
    version: "1.104.X",
    server_status: "online",
    maintenance_mode: false,
    force_update: false
  };
  if (user && sessions[sessionId] && new Date(sessions[sessionId].expireAt) > new Date()) {
    // Kimlik doğrulanmış kullanıcıya özel özellikler
    const features = user.features || {};
    const patchFilename = `modded_${user.owner || 'user'}.unity3d`;
    const patchUrl = `http://${req.hostname}:${globalConfig.port}/assets/${patchFilename}`;
    // Varlık hash'i oluştur (basit)
    const patchHash = crypto.createHash('sha256').update(JSON.stringify(features)).digest('hex').substring(0, 8);
    res.json({
      ...baseResponse,
      patch_url: patchUrl,
      patch_size: JSON.stringify(features).length,
      patch_hash: patchHash,
      features: {
        speed: { enabled: features.speed || false, multiplier: features.speed_multiplier || 1.0 },
        hs_neck: { enabled: features.hs_neck || false },
        high_jump: { enabled: features.high_jump || false, height: features.jump_height || 0.8 },
        aimbot_head: { enabled: features.aimbot_head || false, smooth: features.aimbot_smooth || 0.5 },
        hologram: { enabled: features.hologram || false },
        recoil_zero: { enabled: features.recoil_zero || false },
        auto_fire: { enabled: features.auto_fire || false },
        teleport: { enabled: features.teleport || false },
        anti_ban: { enabled: features.anti_ban || false }
      }
    });
  } else {
    // Kimlik doğrulanmamış, özellikler kapalı
    res.json({
      ...baseResponse,
      features: {
        speed: { enabled: false },
        hs_neck: { enabled: false },
        high_jump: { enabled: false },
        aimbot_head: { enabled: false },
        hologram: { enabled: false },
        recoil_zero: { enabled: false },
        auto_fire: { enabled: false },
        teleport: { enabled: false },
        anti_ban: { enabled: false }
      }
    });
  }
});

// POST /api/config - Kullanıcı ayarlarını günceller
app.post('/api/config', authMiddleware, (req, res) => {
  const user = users[req.userKey];
  const config = req.body;
  // Desteklenen özellik anahtarları
  const allowed = ['speed', 'speed_multiplier', 'hs_neck', 'high_jump', 'jump_height', 'aimbot_head', 'aimbot_smooth', 'hologram', 'recoil_zero', 'auto_fire', 'teleport', 'anti_ban'];
  Object.keys(config).forEach(k => {
    if (allowed.includes(k)) {
      user.features[k] = config[k];
    }
  });
  saveUsers();
  addLog(req.userKey, req.ip, '/api/config');
  res.json({ status: 'ok', features: user.features });
});

// POST /api/toggle - Tek bir özelliği açar/kapatur
app.post('/api/toggle', authMiddleware, (req, res) => {
  const { feature, status } = req.body;
  const user = users[req.userKey];
  if (!user.features) user.features = {};
  if (typeof status !== 'boolean') return res.status(400).json({ error: 'status boolean olmalı' });
  const allowed = ['speed', 'hs_neck', 'high_jump', 'aimbot_head', 'hologram', 'recoil_zero', 'auto_fire', 'teleport', 'anti_ban'];
  if (!allowed.includes(feature)) return res.status(400).json({ error: 'Geçersiz özellik' });
  user.features[feature] = status;
  saveUsers();
  addLog(req.userKey, req.ip, '/api/toggle');
  res.json({ status: 'ok', [feature]: status });
});

// POST /api/add-ip - Mevcut IP'yi kullanıcının cihaz listesine ekler (max_devices kontrolü)
app.post('/api/add-ip', authMiddleware, (req, res) => {
  const user = users[req.userKey];
  const clientIp = req.ip;
  if (!user.devices.includes(clientIp)) {
    if (user.devices.length >= user.max_devices) {
      return res.status(403).json({ error: 'Maksimum cihaz sınırına ulaşıldı' });
    }
    user.devices.push(clientIp);
    saveUsers();
  }
  addLog(req.userKey, clientIp, '/api/add-ip');
  res.json({ status: 'ok', devices: user.devices });
});

// GET /api/status - Kullanıcı oturum durumu
app.get('/api/status', authMiddleware, (req, res) => {
  const user = users[req.userKey];
  const session = sessions[req.headers['x-session-id']];
  res.json({
    session_id: req.headers['x-session-id'],
    user_key: req.userKey,
    owner: user.owner,
    expires: user.expires,
    devices: user.devices,
    features: user.features,
    session_expires: session.expireAt
  });
});

// GET /api/logs - Kullanıcıya ait son loglar
app.get('/api/logs', authMiddleware, (req, res) => {
  const userLogs = logs.filter(l => l.userKey === req.userKey).slice(-100);
  res.json(userLogs);
});

// --------------------------------------
// VARLIK (ASSET) YÖNETİMİ
// --------------------------------------
const ASSETS_DIR = path.join(__dirname, 'assets');
if (!fs.existsSync(ASSETS_DIR)) fs.mkdirSync(ASSETS_DIR);

// GET /assets/:filename - Varlık isteği, yoksa oluştur ve sun
app.get('/assets/:filename', (req, res) => {
  const filePath = path.join(ASSETS_DIR, req.params.filename);
  // Oturumdan kullanıcıyı bul (query veya header)
  let sessionId = req.headers['x-session-id'] || req.query.session_id;
  let user = null;
  if (sessionId && sessions[sessionId]) {
    user = users[sessions[sessionId].userKey];
  }
  if (!user && req.query.session_id) {
    // Belki session_id query ile gelmiştir
    sessionId = req.query.session_id;
    if (sessions[sessionId]) user = users[sessions[sessionId].userKey];
  }

  // Varlık içeriği: kullanıcı özelliklerini içeren JSON + bütünlük hash
  const features = user ? user.features : {};
  const content = {
    generated: new Date().toISOString(),
    features: features,
    user: user ? user.owner : 'public'
  };
  const contentStr = JSON.stringify(content);
  const hash = crypto.createHash('sha256').update(contentStr).digest('hex');

  // Dosyayı oluştur ya da güncelle
  if (!fs.existsSync(filePath)) {
    const finalContent = { ...content, integrity: hash };
    fs.writeFileSync(filePath, JSON.stringify(finalContent));
  } else {
    // Cache süresi dolmuş mu? Basitçe dosyanın son değiştirilme tarihine bak
    const stats = fs.statSync(filePath);
    const ageSeconds = (Date.now() - stats.mtimeMs) / 1000;
    if (ageSeconds > globalConfig.assetCacheSeconds) {
      const finalContent = { ...content, integrity: hash };
      fs.writeFileSync(filePath, JSON.stringify(finalContent));
    }
  }
  res.sendFile(filePath);
});

// --------------------------------------
// FRIDA SCRIPTS ENDPOINT
// --------------------------------------
// Her özellik için Frida betiği döndürür
app.get('/scripts/:feature', (req, res) => {
  const feature = req.params.feature;
  let script = '';
  switch (feature) {
    case 'hs_neck':
      script = `
// hs_neck.js - Kafadan boyun vuruşu (HS Neck) Frida betiği
// Free Fire için zırh çarpanını sıfırlar, tüm vuruşları kafa olarak sayar.
Interceptor.attach(Module.findExportByName(null, 'PlayerInfo_get_armor'), {
  onLeave(retval) {
    retval.replace(0);
  }
});
// Silah hasar çarpanı kısmını doğrudan kafaya yönlendir
Interceptor.attach(Module.findExportByName(null, 'Weapon_get_damageMultiplier'), {
  onLeave(retval) {
    retval.replace(4.0); // 4x kafa hasarı
  }
});
      `;
      break;
    case 'aimbot_head':
      script = `
// aimbot_head.js - Yumuşak aimbot (baş hedefleme)
// Hedefi yumuşakça başa kilitler
const Unity = Module.findExportByName(null, 'UnityEngine_Camera_WorldToScreenPoint');
Interceptor.attach(Unity, {
  onEnter(args) {
    // Hedef pozisyonunu ayarla (basitleştirilmiş, gerçekte Player pozisyonu okunmalı)
    this.target = args[0];
  },
  onLeave(retval) {
    // retval üzerinde ekran koordinatlarını değiştirerek başı hedefle
    retval.add(0).writeFloat(retval.readFloat() + 0.01); // hassas kaydırma
  }
});
      `;
      break;
    case 'hologram':
      script = `
// hologram.js - Duvar arkası görme (wallhack)
// Malzeme render'ını değiştir, düşmanları shader üzerinden görünür yap
const setShader = Module.findExportByName(null, 'Material_SetShader');
Interceptor.attach(setShader, {
  onEnter(args) {
    // Düşman malzemesi ise, shader'ı "Sprites/Default" yap (opaklık artır)
    const materialName = args[0].readCString();
    if (materialName && materialName.includes('Enemy')) {
      const newShader = Module.findBaseAddress('UnityEngine.dll').add(0x12A34).readPointer(); // örnek adres
      args[1] = newShader;
    }
  }
});
      `;
      break;
    case 'recoil_zero':
      script = `
// recoil_zero.js - Geri tepme sıfırlama
// Silahın geri tepme animasyonunu durdur
Interceptor.attach(Module.findExportByName(null, 'Weapon_ApplyRecoil'), {
  onEnter(args) {
    args[0] = ptr(0); // Null yaparak fonksiyonu atla
  }
});
      `;
      break;
    case 'auto_fire':
      script = `
// auto_fire.js - Otomatik ateş
// Düşman algılandığında tetik çekme fonksiyonunu çağır
const shootMethod = Module.findExportByName(null, 'Player_Shoot');
const enemyCheck = Module.findExportByName(null, 'GameManager_IsEnemyInSight');
Interceptor.attach(enemyCheck, {
  onLeave(retval) {
    if (retval.toInt32() === 1) {
      // Oyuncu referansına ihtiyaç var, burada sabit adres kullanılarak çağrılabilir
      const localPlayer = Module.findBaseAddress('Assembly-CSharp.dll').add(0x43210).readPointer();
      new NativeFunction(shootMethod, 'void', ['pointer'])(localPlayer);
    }
  }
});
      `;
      break;
    default:
      return res.status(404).json({ error: 'Script bulunamadı' });
  }
  res.setHeader('Content-Type', 'application/javascript');
  res.send(script.trim());
});

// --------------------------------------
// KULLANICI DASHBOARD (HTML)
// --------------------------------------
app.get('/dashboard', (req, res) => {
  // Sadece oturum açmış kullanıcılar görebilir; basit HTML sliderlar
  const sessionId = req.headers['x-session-id'] || req.query.session_id;
  const user = sessionId ? users[sessions[sessionId]?.userKey] : null;
  if (!user) return res.status(401).send('Lütfen önce /auth ile giriş yapın');

  const features = user.features || {};
  const html = `
  <!DOCTYPE html>
  <html>
  <head><meta charset="UTF-8"><title>Free Fire Proxy Panel</title>
  <style>
    body { background:#0a0a0a; color:#0f0; font-family:monospace; }
    .feature { margin:10px 0; }
    input[type=range] { width:200px; }
  </style>
  </head>
  <body>
  <h2>Proxy Ayarları - ${user.owner}</h2>
  <form id="configForm">
  <div class="feature"><label>Hız Çarpanı: <input type="range" name="speed_multiplier" min="1" max="10" step="0.1" value="${features.speed_multiplier || 1.0}"> <span id="speedVal">${features.speed_multiplier || 1.0}</span></label></div>
  <div class="feature"><label>HS Neck: <input type="checkbox" name="hs_neck" ${features.hs_neck ? 'checked' : ''}></label></div>
  <div class="feature"><label>High Jump: <input type="checkbox" name="high_jump" ${features.high_jump ? 'checked' : ''}></label></div>
  <div class="feature"><label>Aimbot Baş: <input type="checkbox" name="aimbot_head" ${features.aimbot_head ? 'checked' : ''}></label></div>
  <div class="feature"><label>Hologram (Wallhack): <input type="checkbox" name="hologram" ${features.hologram ? 'checked' : ''}></label></div>
  <div class="feature"><label>Geri Tepme Sıfır: <input type="checkbox" name="recoil_zero" ${features.recoil_zero ? 'checked' : ''}></label></div>
  <div class="feature"><label>Oto Ateş: <input type="checkbox" name="auto_fire" ${features.auto_fire ? 'checked' : ''}></label></div>
  <div class="feature"><label>Teleport: <input type="checkbox" name="teleport" ${features.teleport ? 'checked' : ''}></label></div>
  <div class="feature"><label>Anti-Ban: <input type="checkbox" name="anti_ban" ${features.anti_ban ? 'checked' : ''}></label></div>
  <button type="button" onclick="saveConfig()">Ayarları Kaydet</button>
  </form>
  <p id="status"></p>
  <script>
    const sessionId = '${sessionId}';
    function saveConfig() {
      const form = document.getElementById('configForm');
      const data = {
        speed_multiplier: parseFloat(form.speed_multiplier.value),
        hs_neck: form.hs_neck.checked,
        high_jump: form.high_jump.checked,
        aimbot_head: form.aimbot_head.checked,
        hologram: form.hologram.checked,
        recoil_zero: form.recoil_zero.checked,
        auto_fire: form.auto_fire.checked,
        teleport: form.teleport.checked,
        anti_ban: form.anti_ban.checked
      };
      fetch('/api/config', {
        method:'POST',
        headers: { 'Content-Type':'application/json', 'X-Session-ID': sessionId },
        body: JSON.stringify(data)
      }).then(r=>r.json()).then(d=>{
        document.getElementById('status').innerText = 'Kaydedildi!';
      });
    }
    document.querySelectorAll('input[type=range]').forEach(el => el.oninput = function(e){ document.getElementById('speedVal').innerText = e.target.value; });
  </script>
  </body>
  </html>
  `;
  res.send(html);
});

// --------------------------------------
// ADMIN PANELİ
// --------------------------------------
app.get('/admin', adminAuth, (req, res) => {
  const userList = Object.entries(users).map(([key, u]) => ({
    key,
    owner: u.owner,
    expires: u.expires,
    devices: u.devices.length,
    max: u.max_devices
  }));
  let html = `<html><head><title>Admin Panel</title></head><body><h2>Kullanıcılar</h2><table border="1"><tr><th>Anahtar</th><th>Sahip</th><th>Bitiş</th><th>Cihaz</th><th>İşlem</th></tr>`;
  userList.forEach(u => {
    html += `<tr><td>${u.key}</td><td>${u.owner}</td><td>${u.expires}</td><td>${u.devices}/${u.max}</td><td><button onclick="block('${u.key}')">Engelle</button></td></tr>`;
  });
  html += `</table><br/><input id="newKey" placeholder="369SD-XXXXXX" /><input id="newOwner" placeholder="Sahip" /><button onclick="createKey()">Oluştur</button><script>
    function block(key) { fetch('/admin/block?key='+key,{headers:{'X-Admin-Pass':'${globalConfig.adminPassword}'}}).then(r=>alert('Engellendi')); }
    function createKey() { fetch('/admin/create',{method:'POST',headers:{'Content-Type':'application/json','X-Admin-Pass':'${globalConfig.adminPassword}'},body:JSON.stringify({key:document.getElementById('newKey').value,owner:document.getElementById('newOwner').value})}).then(r=>r.json()).then(d=>alert(d.msg || d.error)); }
  </script></body></html>`;
  res.send(html);
});

app.post('/admin/create', adminAuth, (req, res) => {
  const { key, owner } = req.body;
  if (!isValidKey(key)) return res.status(400).json({ error: 'Geçersiz anahtar formatı' });
  if (users[key]) return res.status(409).json({ error: 'Anahtar zaten var' });
  users[key] = {
    owner: owner || 'user',
    expires: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString(), // 30 gün
    max_devices: 50,
    features: {},
    devices: []
  };
  saveUsers();
  res.json({ msg: 'Anahtar oluşturuldu', key });
});

app.get('/admin/block', adminAuth, (req, res) => {
  const key = req.query.key;
  if (users[key]) {
    delete users[key];
    saveUsers();
    // ilişkili oturumları sil
    Object.keys(sessions).forEach(sid => {
      if (sessions[sid].userKey === key) delete sessions[sid];
    });
    saveSessions();
    res.json({ msg: 'Kullanıcı engellendi' });
  } else res.status(404).json({ error: 'Kullanıcı bulunamadı' });
});

// --------------------------------------
// SUNUCU BAŞLATMA
// --------------------------------------
app.listen(globalConfig.port, () => {
  console.log(`Proxy sunucusu http://0.0.0.0:${globalConfig.port} adresinde çalışıyor.`);
  // Varsayılan bir kullanıcı yoksa test anahtarı oluştur
  if (Object.keys(users).length === 0) {
    users['369SD-TEST01'] = {
      owner: 'TestUser',
      expires: new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString(),
      max_devices: 5,
      features: {
        speed: true,
        speed_multiplier: 3.8,
        hs_neck: true,
        high_jump: true,
        jump_height: 0.8,
        aimbot_head: true,
        aimbot_smooth: 0.5,
        hologram: true,
        recoil_zero: true,
        auto_fire: false,
        teleport: false,
        anti_ban: false
      },
      devices: []
    };
    saveUsers();
    console.log('Test anahtarı oluşturuldu: 369SD-TEST01');
  }
});
```

### package.json içeriği (ayrı dosya):
```json
{
  "name": "freefire-proxy",
  "version": "1.0.0",
  "description": "Free Fire Proxy with Frida scripts and asset management",
  "main": "proxy.js",
  "scripts": {
    "start": "node proxy.js"
  },
  "dependencies": {
    "express": "^4.18.2",
    "jsonwebtoken": "^9.0.0",
    "uuid": "^9.0.0"
  }
}
```

### ÇALIŞTIRMA TALİMATLARI:
1. `npm install express jsonwebtoken uuid` ile bağımlılıkları yükleyin.
2. `node proxy.js` ile sunucuyu başlatın.
3. Oyunda localConfig.json dosyasına sunucu IP ve portu yazın: `"proxyHost": "http://SUNUCU_IP:4500"`, `"versionUrl": "http://SUNUCU_IP:4500/version.php"`.
4. İlk giriş için `POST /auth` ile anahtar doğrulayın, dönen `session_id`'yi saklayın.
5. Dashboard `/dashboard` üzerinden ayarları yönetin, Frida scriptlerini `/scripts` altından alın.
6. Frida ile script'i enjekte edin: `frida -U -n com.dts.freefireth -l hs_neck.js`.
